import{_ as e,o as a,c as o,ag as l}from"./chunks/framework.ePeAWSvT.js";const g=JSON.parse('{"title":"🔌 보너스: AI에게 USB-C 포트 달아주기","description":"","frontmatter":{},"headers":[],"relativePath":"학습자료/3-바이브코딩기초/3-3-mcp설명.md","filePath":"학습자료/3-바이브코딩기초/3-3-mcp설명.md"}'),s={name:"학습자료/3-바이브코딩기초/3-3-mcp설명.md"};function n(d,t,r,i,c,p){return a(),o("div",null,[...t[0]||(t[0]=[l(`<h1 id="🔌-보너스-ai에게-usb-c-포트-달아주기" tabindex="-1">🔌 보너스: AI에게 USB-C 포트 달아주기 <a class="header-anchor" href="#🔌-보너스-ai에게-usb-c-포트-달아주기" aria-label="Permalink to &quot;🔌 보너스: AI에게 USB-C 포트 달아주기&quot;">​</a></h1><blockquote><p>오늘 세미나에서 잠깐 언급된 MCP, 조금 더 쉽게 설명해드릴게요. 지금 당장 몰라도 괜찮습니다. &quot;이런 게 가능하구나!&quot; 정도만 알아가세요.</p></blockquote><hr><h2 id="한-줄-요약" tabindex="-1">한 줄 요약 <a class="header-anchor" href="#한-줄-요약" aria-label="Permalink to &quot;한 줄 요약&quot;">​</a></h2><blockquote><p><strong>&quot;MCP는 AI에게 새로운 능력을 추가하는 USB-C 포트입니다.&quot;</strong></p></blockquote><hr><h2 id="usb-c-비유로-이해하기" tabindex="-1">USB-C 비유로 이해하기 <a class="header-anchor" href="#usb-c-비유로-이해하기" aria-label="Permalink to &quot;USB-C 비유로 이해하기&quot;">​</a></h2><p>노트북에 USB-C 포트가 있으면 다양한 장치를 꽂아서 기능을 늘릴 수 있죠. MCP도 똑같습니다. AI에 연결하면 AI가 할 수 있는 일이 늘어납니다.</p><table tabindex="0"><thead><tr><th style="text-align:center;">🔌 USB-C에 꽂는 것</th><th style="text-align:center;">생기는 능력</th><th style="text-align:center;">🤖 MCP에 연결하는 것</th><th style="text-align:center;">AI가 얻는 능력</th></tr></thead><tbody><tr><td style="text-align:center;">충전기</td><td style="text-align:center;">충전</td><td style="text-align:center;">Google Calendar</td><td style="text-align:center;">일정 관리</td></tr><tr><td style="text-align:center;">모니터</td><td style="text-align:center;">화면 확장</td><td style="text-align:center;">Notion</td><td style="text-align:center;">DB 읽기/쓰기</td></tr><tr><td style="text-align:center;">USB 메모리</td><td style="text-align:center;">파일 전송</td><td style="text-align:center;">파일 시스템</td><td style="text-align:center;">내 파일 접근</td></tr><tr><td style="text-align:center;">키보드</td><td style="text-align:center;">입력 장치</td><td style="text-align:center;">Slack</td><td style="text-align:center;">메시지 전송</td></tr></tbody></table><hr><h2 id="mcp-없을-때-vs-mcp-있을-때" tabindex="-1">MCP 없을 때 vs MCP 있을 때 <a class="header-anchor" href="#mcp-없을-때-vs-mcp-있을-때" aria-label="Permalink to &quot;MCP 없을 때 vs MCP 있을 때&quot;">​</a></h2><p>실제로 어떻게 다른지 대화로 느껴보세요.</p><h3 id="😔-mcp-없을-때" tabindex="-1">😔 MCP 없을 때 <a class="header-anchor" href="#😔-mcp-없을-때" aria-label="Permalink to &quot;😔 MCP 없을 때&quot;">​</a></h3><blockquote><p>👤 나: &quot;오늘 오후 3시에 팀 미팅 잡아줘.&quot;</p><p>🤖 AI: &quot;죄송해요, 저는 캘린더에 접근할 수 없어요. 직접 추가해주세요.&quot;</p></blockquote><blockquote><p>👤 나: &quot;지난주에 보낸 이메일 좀 찾아줘.&quot;</p><p>🤖 AI: &quot;저는 이메일에 접근할 수 없어요. 제목이나 내용을 직접 복사해주시면 도와드릴게요.&quot;</p></blockquote><hr><h3 id="😊-mcp-있을-때-google-calendar-연결-후" tabindex="-1">😊 MCP 있을 때 (Google Calendar 연결 후) <a class="header-anchor" href="#😊-mcp-있을-때-google-calendar-연결-후" aria-label="Permalink to &quot;😊 MCP 있을 때 (Google Calendar 연결 후)&quot;">​</a></h3><blockquote><p>👤 나: &quot;오늘 오후 3시에 팀 미팅 잡아줘.&quot;</p><p>🤖 AI: &quot;네! 오늘 오후 3시에 &#39;팀 미팅&#39; 일정을 추가했습니다. 참석자 초대도 할까요?&quot;</p></blockquote><blockquote><p>👤 나: &quot;내일 비어있는 시간대 알려줘.&quot;</p><p>🤖 AI: &quot;내일 오전 10시~12시, 오후 2시~4시가 비어있습니다. 어떤 일정 잡아드릴까요?&quot;</p></blockquote><div class="tip custom-block"><p class="custom-block-title">MCP가 연결되면 달라지는 것</p><p>AI가 단순히 텍스트를 생성하는 것을 넘어서, <strong>실제로 외부 서비스를 읽고, 쓰고, 실행</strong>할 수 있게 됩니다. &quot;도와주는 챗봇&quot;에서 &quot;진짜 업무를 처리하는 비서&quot;로 업그레이드되는 거예요.</p></div><hr><h2 id="mcp-서버와-tools-—-앱과-버튼" tabindex="-1">MCP 서버와 Tools — 앱과 버튼 <a class="header-anchor" href="#mcp-서버와-tools-—-앱과-버튼" aria-label="Permalink to &quot;MCP 서버와 Tools — 앱과 버튼&quot;">​</a></h2><p>MCP를 더 정확하게 이해해볼까요?</p><p><strong>MCP 서버</strong> = 스마트폰의 <strong>앱</strong><strong>Tool</strong> = 앱 안의 <strong>기능 버튼</strong></p><p>예를 들어, 스마트폰에 &quot;카카오톡&quot; 앱을 설치하면 &quot;메시지 보내기&quot;, &quot;사진 보내기&quot;, &quot;통화하기&quot; 등 여러 기능을 쓸 수 있죠?</p><p>MCP도 같습니다:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>📱 Google Calendar MCP 서버 (= 앱)</span></span>
<span class="line"><span>├── 🔧 일정 조회 (Tool)</span></span>
<span class="line"><span>├── 🔧 일정 생성 (Tool)</span></span>
<span class="line"><span>├── 🔧 일정 수정 (Tool)</span></span>
<span class="line"><span>└── 🔧 일정 삭제 (Tool)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>📱 Notion MCP 서버 (= 앱)</span></span>
<span class="line"><span>├── 🔧 페이지 읽기 (Tool)</span></span>
<span class="line"><span>├── 🔧 페이지 생성 (Tool)</span></span>
<span class="line"><span>├── 🔧 데이터베이스 조회 (Tool)</span></span>
<span class="line"><span>└── 🔧 댓글 추가 (Tool)</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">핵심 구분</p><ul><li><strong>MCP 서버 1개를 연결</strong> = 앱 1개 설치</li><li><strong>Tool 여러 개 사용 가능</strong> = 앱 안의 기능 여러 개 사용</li></ul></div><hr><h2 id="이런-말을-하면-→-이-tool이-호출됩니다" tabindex="-1">이런 말을 하면 → 이 Tool이 호출됩니다 <a class="header-anchor" href="#이런-말을-하면-→-이-tool이-호출됩니다" aria-label="Permalink to &quot;이런 말을 하면 → 이 Tool이 호출됩니다&quot;">​</a></h2><p>MCP가 연결되어 있으면, 자연어로 말해도 AI가 알아서 맞는 Tool을 골라 실행합니다.</p><table tabindex="0"><thead><tr><th style="text-align:left;">💬 내가 하는 말</th><th style="text-align:left;">🔧 호출되는 Tool</th><th style="text-align:left;">📱 MCP 서버</th></tr></thead><tbody><tr><td style="text-align:left;">&quot;내일 일정 알려줘&quot;</td><td style="text-align:left;"><code>list-events</code></td><td style="text-align:left;">Google Calendar</td></tr><tr><td style="text-align:left;">&quot;오후 3시에 미팅 잡아줘&quot;</td><td style="text-align:left;"><code>create-event</code></td><td style="text-align:left;">Google Calendar</td></tr><tr><td style="text-align:left;">&quot;프로젝트 DB에서 진행중인 것만 보여줘&quot;</td><td style="text-align:left;"><code>notion-search</code></td><td style="text-align:left;">Notion</td></tr><tr><td style="text-align:left;">&quot;이 내용으로 노션 페이지 만들어줘&quot;</td><td style="text-align:left;"><code>notion-create-pages</code></td><td style="text-align:left;">Notion</td></tr><tr><td style="text-align:left;">&quot;드라이브에서 보고서 파일 찾아줘&quot;</td><td style="text-align:left;"><code>search-files</code></td><td style="text-align:left;">Google Drive</td></tr><tr><td style="text-align:left;">&quot;#general 채널에 메시지 보내줘&quot;</td><td style="text-align:left;"><code>send-message</code></td><td style="text-align:left;">Slack</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">마법이 아닙니다</p><p>AI가 &quot;내일 일정&quot;이라는 키워드를 보고, 연결된 MCP 서버 중 Calendar의 <code>list-events</code> Tool이 적합하다고 <strong>자동 판단</strong>하는 겁니다. 여러분은 그냥 자연어로 말하면 됩니다!</p></div><hr><h2 id="연결-가능한-대표-서비스" tabindex="-1">연결 가능한 대표 서비스 <a class="header-anchor" href="#연결-가능한-대표-서비스" aria-label="Permalink to &quot;연결 가능한 대표 서비스&quot;">​</a></h2><h3 id="google-서비스" tabindex="-1">Google 서비스 <a class="header-anchor" href="#google-서비스" aria-label="Permalink to &quot;Google 서비스&quot;">​</a></h3><table tabindex="0"><thead><tr><th>서비스</th><th>MCP 서버</th><th>AI가 할 수 있는 것</th></tr></thead><tbody><tr><td><strong>Google Calendar</strong></td><td><code>google-calendar</code></td><td>일정 조회, 추가, 수정, 삭제, 빈 시간 확인</td></tr><tr><td><strong>Google Drive</strong></td><td><code>google-drive</code></td><td>파일 검색, 내용 읽기, 폴더 탐색</td></tr><tr><td><strong>Google Sheets</strong></td><td><code>google-sheets</code></td><td>스프레드시트 읽기, 셀 수정, 데이터 분석</td></tr><tr><td><strong>Gmail</strong></td><td><code>gmail</code></td><td>이메일 읽기, 보내기, 검색, 라벨 관리</td></tr></tbody></table><h3 id="업무-도구" tabindex="-1">업무 도구 <a class="header-anchor" href="#업무-도구" aria-label="Permalink to &quot;업무 도구&quot;">​</a></h3><table tabindex="0"><thead><tr><th>서비스</th><th>MCP 서버</th><th>AI가 할 수 있는 것</th></tr></thead><tbody><tr><td><strong>Notion</strong></td><td><code>notion</code></td><td>페이지/DB CRUD, 검색, 댓글</td></tr><tr><td><strong>Slack</strong></td><td><code>slack</code></td><td>메시지 읽기/보내기, 채널 관리</td></tr><tr><td><strong>GitHub</strong></td><td><code>github</code></td><td>코드 관리, PR, 이슈 등록</td></tr><tr><td><strong>파일 시스템</strong></td><td><code>filesystem</code></td><td>내 컴퓨터 파일 읽기/쓰기</td></tr><tr><td><strong>웹 브라우저</strong></td><td><code>browser</code></td><td>웹 검색, 페이지 내용 읽기</td></tr></tbody></table><hr><h2 id="😌-당장-안-해도-됩니다" tabindex="-1">😌 당장 안 해도 됩니다! <a class="header-anchor" href="#😌-당장-안-해도-됩니다" aria-label="Permalink to &quot;😌 당장 안 해도 됩니다!&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">오늘 꼭 설정할 필요 없어요</p><p>MCP 설정은 오늘 세미나 범위 밖입니다.</p><p><strong>스킬 하나 잘 쓰는 게 MCP 10개 설정보다 훨씬 중요합니다.</strong></p><p>지금은 &quot;이런 게 가능하구나!&quot; 정도만 알고 가세요. 익숙해지면 자연스럽게 하게 됩니다.</p></div><hr><h2 id="관심-있으면-여기서-시작하세요" tabindex="-1">관심 있으면 여기서 시작하세요 <a class="header-anchor" href="#관심-있으면-여기서-시작하세요" aria-label="Permalink to &quot;관심 있으면 여기서 시작하세요&quot;">​</a></h2><p>준비가 됐다 싶을 때, 이 순서대로 따라오세요.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>① 스킬을 2~3주 실제 업무에서 써본다</span></span>
<span class="line"><span>      ↓</span></span>
<span class="line"><span>② &quot;AI가 캘린더까지 써줬으면 좋겠다&quot; 싶은 순간이 온다</span></span>
<span class="line"><span>      ↓</span></span>
<span class="line"><span>③ Google Calendar MCP부터 시작한다 (가장 쉽고 실용적)</span></span>
<span class="line"><span>      ↓</span></span>
<span class="line"><span>④ 설정 가이드 한 줄씩 따라한다 (터미널 명령어 1줄로 설치)</span></span>
<span class="line"><span>      ↓</span></span>
<span class="line"><span>⑤ &quot;내일 오전 10시 팀 미팅 잡아줘&quot; 가 실제로 된다 🎉</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">설정 방식은 어렵지 않아요</p><p>대부분의 MCP 설정은 이 3단계를 따릅니다.</p><ol><li>MCP 서버 설치 (터미널 명령어 한 줄)</li><li>설정 파일에 서비스 정보 입력</li><li>Claude Code 재시작</li></ol><p>가이드만 따라하면 비개발자도 충분히 할 수 있는 수준입니다. 궁금한 점은 커뮤니티에서 편하게 질문해주세요!</p></div><hr><h2 id="핵심만-기억하세요" tabindex="-1">핵심만 기억하세요 <a class="header-anchor" href="#핵심만-기억하세요" aria-label="Permalink to &quot;핵심만 기억하세요&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">오늘의 핵심 포인트</p><p>MCP를 당장 설정하지 않아도 됩니다.</p><p>중요한 건: <strong>&quot;AI가 외부 도구와 연결될 수 있다&quot;</strong> 는 가능성을 아는 것입니다.</p><p>성장 순서는 이렇습니다.</p><p><strong>스킬 → CLAUDE.md → MCP</strong></p><p>차근차근, 한 걸음씩. 그게 가장 빠른 길입니다. 🚀</p></div>`,50)])])}const u=e(s,[["render",n]]);export{g as __pageData,u as default};
